    //////////////////////////////////////////////////////////////*/

    /**
     * @notice Collection constructor; pass-through while setting the admin to the sender
     *         see {BeaconProxy.constructor} for more details
     * @custom:event {ERC1967Upgrade.AdminChanged}
     */
